var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。`,ENG:`that you'll be with him, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called him to your office. He said he'd be here soon.`,TWN:`做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SNIPE_SL_NULL_NULL`,text:{KOREA:`이번엔 무슨 일로 부르셨습니까, 사장님?`,JPN:`今日はどういったご用件ですか？　社長。`,ENG:`What can I do for you this time, Boss?`,TWN:`這次您找我有什麼事嗎，老闆？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPE_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SNIPE_SL_NULL_NULL`,text:{KOREA:`......종신계약?`,JPN:`……終身契約？`,ENG:`A lifetime contract?`,TWN:`......終身契約？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPE_SL_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SNIPE_SL_NULL_NULL`,text:{KOREA:`아하, 그러니까... 믿을 수 있는 경호가 필요하단 말씀이시군요.`,JPN:`なるほど、つまり……信用に足る護衛が必要ということですね。`,ENG:`Aha, I get it. You need a bodyguard you can trust, don't you?`,TWN:`啊哈，所以......您是說您需要一個可以信賴的保鏢吧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPE_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SNIPE_SL_NULL_NULL`,text:{KOREA:`이제야 드리는 말씀이지만, 제겐 사장님이 모르시는 한 가지 비밀이 있습니다.`,JPN:`今さらなお話ですが、私には社長がご存知でない秘密が一つあります。`,ENG:`I'm sorry, but there's something about me that I haven't told you.`,TWN:`雖然我現在才說，但其實我有一個老闆不知道的秘密。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPE_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`SNIPE_SL_NULL_NULL`,text:{KOREA:`저격수선발과정에서, 제가 양쪽 눈이 짝짝이란 사실을 속이고 입대했거든요.`,JPN:`私は狙撃手選抜過程において、両目の視力が異なることを隠して入隊しているのです。`,ENG:`When I applied for the sniper job, I didn't tell anyone that I have anisometropia.`,TWN:`在狙擊手選拔的過程中，我隱瞞了自己兩眼不對稱的事實才入隊的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPE_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`SNIPE_SL_NULL_NULL`,text:{KOREA:`하하, 그렇다고 제 실력에 하자가 있다는 뜻은 아닙니다.`,JPN:`ハハ、とは言いましても、実力は変わらないですけどね。`,ENG:`Hah hah, that doesn't mean my skills are poor.`,TWN:`哈哈，但這不意味著我欠缺實力。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPE_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`SNIPE_SL_NULL_NULL`,text:{KOREA:`그냥 저를 믿어주시는 것 같으니, 저도 비밀 한 톨 남기지 말아야겠다 싶어서요.`,JPN:`信用していただいている以上、こちらも一切の隠し立てをしないことが筋だと思ったまでです。`,ENG:`Since you trust me, I've decided to be completely honest with you.`,TWN:`只是因為您信任我，所以我也不想保留什麼秘密。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPE_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`SNIPE_SL_NULL_NULL`,text:{KOREA:`그럼 잘 부탁 드리겠습니다.`,JPN:`では、よろしくお願いします。`,ENG:`Thank you for choosing me.`,TWN:`那就請多多指教了。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPE_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};